={{ (function() {
  var qs = $input.first().json.query || $input.first().json.params || {};
  var tenantId = String(qs.tenantId || '').replace(/[^a-f0-9-]/gi, '').substring(0, 36);
  if (!tenantId) return "SELECT '[]'::json as data";

  var from = String(qs.from || '').replace(/[^0-9-]/g, '').substring(0, 10);
  var to = String(qs.to || '').replace(/[^0-9-]/g, '').substring(0, 10);

  var sql = "SELECT id, nom, prenom, telephone, email, source, notes, "
    + "date_entretien, type_entretien, date_contact, statut, score, created_at "
    + "FROM leads WHERE tenant_id = '" + tenantId + "' "
    + "AND (source LIKE '%rdv%' OR source LIKE '%entretien%' OR date_entretien IS NOT NULL) ";

  if (from) sql += "AND (date_entretien >= '" + from + "' OR (date_entretien IS NULL AND created_at >= '" + from + "')) ";
  if (to) sql += "AND (date_entretien <= '" + to + "T23:59:59' OR (date_entretien IS NULL AND created_at <= '" + to + "T23:59:59')) ";

  sql += "ORDER BY COALESCE(date_entretien, created_at) DESC LIMIT 200";
  return sql;
})() }}

