// Parse leads into calendar events
var rows = $('02. Query RDV').all();
var events = [];

for (var i = 0; i < rows.length; i++) {
  var r = rows[i].json || rows[i];
  var ev = {
    id: r.id || '',
    title: '',
    start: null,
    end: null,
    type: r.type_entretien || 'telephonique',
    contact: {
      nom: r.nom || '',
      prenom: r.prenom || '',
      telephone: r.telephone || '',
      email: r.email || ''
    },
    source: r.source || '',
    statut: r.statut || 'nouveau',
    score: r.score || 0,
    notes: r.notes || ''
  };

  // Build title
  var name = ((r.prenom || '') + ' ' + (r.nom || '')).trim() || r.telephone || 'Inconnu';
  ev.title = name;

  // Parse date — priorite: date_entretien > notes > created_at
  if (r.date_entretien) {
    ev.start = r.date_entretien;
    // End = start + 30 min par defaut
    var d = new Date(r.date_entretien);
    d.setMinutes(d.getMinutes() + 30);
    ev.end = d.toISOString();
  } else if (r.notes) {
    // Parse "RDV demande: ... le YYYY-MM-DD a HH:MM"
    var notes = String(r.notes);
    var dateMatch = notes.match(/(\d{4}-\d{2}-\d{2})/);
    var timeMatch = notes.match(/(\d{2}:\d{2})/);
    if (dateMatch) {
      var dateStr = dateMatch[1];
      var timeStr = timeMatch ? timeMatch[1] : '09:00';
      ev.start = dateStr + 'T' + timeStr + ':00';
      var d2 = new Date(ev.start);
      d2.setMinutes(d2.getMinutes() + 30);
      ev.end = d2.toISOString();
    } else {
      // Fallback: created_at
      ev.start = r.created_at;
      ev.end = r.created_at;
      ev.type = 'a_planifier';
    }

    // Extract objet from notes
    var objMatch = notes.match(/RDV demande:\s*(.+?)(?:\s+le\s|$)/);
    if (objMatch) ev.title = objMatch[1].trim() + ' - ' + name;
  } else {
    ev.start = r.created_at;
    ev.end = r.created_at;
    ev.type = 'a_planifier';
  }

  events.push(ev);
}

return [{ json: {
  success: true,
  count: events.length,
  events: events
}}];
